const ICON_CACHE = "public, max-age=31536000, immutable";
const MANIFEST_CACHE = "public, max-age=3600";

type Asset = { contentType: string; cacheControl: string; body: string; encoding: "base64" | "text" };

const ASSETS: Record<string, Asset> = {
  "/favicon.ico": { contentType: "image/x-icon", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/favicon-16x16.png": { contentType: "image/png", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/favicon-32x32.png": { contentType: "image/png", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/apple-touch-icon.png": { contentType: "image/png", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/android-chrome-192x192.png": { contentType: "image/png", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/android-chrome-512x512.png": { contentType: "image/png", cacheControl: ICON_CACHE, encoding: "base64", body: "" },
  "/site.webmanifest": { contentType: "application/manifest+json; charset=utf-8", cacheControl: MANIFEST_CACHE, encoding: "text", body: "{\n  \"name\": \"Droplet Tasks\",\n  \"short_name\": \"Tasks\",\n  \"icons\": [\n    {\n      \"src\": \"/android-chrome-192x192.png\",\n      \"sizes\": \"192x192\",\n      \"type\": \"image/png\"\n    },\n    {\n      \"src\": \"/android-chrome-512x512.png\",\n      \"sizes\": \"512x512\",\n      \"type\": \"image/png\"\n    }\n  ],\n  \"theme_color\": \"#f7f5ef\",\n  \"background_color\": \"#f7f5ef\",\n  \"display\": \"standalone\"\n}" },
};

export function handleAsset(request: Request): Response | null {
  if (request.method !== "GET" && request.method !== "HEAD") return null;
  const url = new URL(request.url);
  const asset = ASSETS[url.pathname];
  if (!asset) return null;
  const headers = { "content-type": asset.contentType, "cache-control": asset.cacheControl };
  if (request.method === "HEAD") return new Response(null, { headers });
  return new Response(asset.encoding === "base64" ? decodeBase64(asset.body) : asset.body, { headers });
}

function decodeBase64(value: string): ArrayBuffer {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) bytes[index] = binary.charCodeAt(index);
  return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
}
